                    { formula: "Kb = [BH⁺][OH⁻] / [B]",           description: "Weak base dissociation constant" },
                    { formula: "Ka × Kb = Kw = 10⁻¹⁴",             description: "Conjugate pair relationship" },
                    { formula: "pKa + pKb = 14",                    description: "Equivalent pK relationship" },
                    { formula: "pH = pKa + log([A⁻]/[HA])",         description: "Henderson-Hasselbalch" },
                    { formula: "% ionisation = (x/Ca) × 100%",      description: "Degree of ionisation" }
