                        cathode: "PbO₂ + SO₄²⁻ + 4H⁺ + 2e⁻ → PbSO₄ + 2H₂O  (discharge)",
                        electrolyte: "H₂SO₄(aq), ~30–40%",
                        EMF: "~2.0 V per cell; typical car battery = 6 cells × 2 V = 12 V",
