                    example: {
                        cell: "Cu | Cu²⁺(0.010 M) || Cu²⁺(1.00 M) | Cu",
                        E: "E = (0.0592/2) log(1.00/0.010) = 0.0296 × 2 = 0.0592 V",
                        direction: "Cu²⁺ reduced at higher concentration side; Cu oxidised at lower concentration side"
                    },
                    application: "Muscle nerve impulse transmission driven by K⁺/Na⁺ concentration gradients across membranes"
