                    { concept: "Neutron number (N)", definition: "N = A − Z" },
                    { concept: "Isotopes", definition: "Same Z, different A (different N)" },
                    { concept: "Cation", definition: "Positive ion; atom lost electrons" },
                    { concept: "Anion", definition: "Negative ion; atom gained electrons" },
                    { concept: "Relative atomic mass", definition: "Weighted average of isotopic masses" },
                    { concept: "Nucleon", definition: "Proton or neutron" }
